"""Tests for mTLS client wrapper.

Tests certificate validation, hostname verification, connection handling,
and certificate rotation for inter-service communication.
"""
import pytest
import ssl
import datetime
from unittest.mock import patch, MagicMock, PropertyMock
from cryptography import x509
from cryptography.x509.oid import NameOID
from cryptography.hazmat.primitives import hashes, serialization
from cryptography.hazmat.primitives.asymmetric import rsa


# ---- helpers to generate test certs ----

def _make_ca_key_and_cert(cn="Windward Test CA"):
    key = rsa.generate_private_key(public_exponent=65537, key_size=2048)
    subject = issuer = x509.Name([x509.NameAttribute(NameOID.COMMON_NAME, cn)])
    cert = (
        x509.CertificateBuilder()
        .subject_name(subject)
        .issuer_name(issuer)
        .public_key(key.public_key())
        .serial_number(x509.random_serial_number())
        .not_valid_before(datetime.datetime.utcnow() - datetime.timedelta(days=1))
        .not_valid_after(datetime.datetime.utcnow() + datetime.timedelta(days=365))
        .add_extension(x509.BasicConstraints(ca=True, path_length=None), critical=True)
        .sign(key, hashes.SHA256())
    )
    return key, cert


def _make_server_cert(ca_key, ca_cert, cn="inventory.windward.internal", sans=None, expired=False, wildcard=False):
    key = rsa.generate_private_key(public_exponent=65537, key_size=2048)
    subject = x509.Name([x509.NameAttribute(NameOID.COMMON_NAME, cn)])
    builder = (
        x509.CertificateBuilder()
        .subject_name(subject)
        .issuer_name(ca_cert.subject)
        .public_key(key.public_key())
        .serial_number(x509.random_serial_number())
    )
    if expired:
        builder = builder.not_valid_before(
            datetime.datetime.utcnow() - datetime.timedelta(days=365)
        ).not_valid_after(
            datetime.datetime.utcnow() - datetime.timedelta(days=1)
        )
    else:
        builder = builder.not_valid_before(
            datetime.datetime.utcnow() - datetime.timedelta(days=1)
        ).not_valid_after(
            datetime.datetime.utcnow() + datetime.timedelta(days=365)
        )

    san_list = []
    if sans:
        for san in sans:
            san_list.append(x509.DNSName(san))
    elif wildcard:
        san_list.append(x509.DNSName(f"*.windward.internal"))
        san_list.append(x509.DNSName(cn))
    else:
        san_list.append(x509.DNSName(cn))

    builder = builder.add_extension(
        x509.SubjectAlternativeName(san_list), critical=False
    )
    cert = builder.sign(ca_key, hashes.SHA256())
    return key, cert


# ---- fixtures ----

@pytest.fixture
def ca_pair():
    return _make_ca_key_and_cert()


@pytest.fixture
def valid_server_cert(ca_pair):
    ca_key, ca_cert = ca_pair
    return _make_server_cert(ca_key, ca_cert)


@pytest.fixture
def expired_server_cert(ca_pair):
    ca_key, ca_cert = ca_pair
    return _make_server_cert(ca_key, ca_cert, expired=True)


@pytest.fixture
def wildcard_server_cert(ca_pair):
    ca_key, ca_cert = ca_pair
    return _make_server_cert(ca_key, ca_cert, cn="windward.internal", wildcard=True)


@pytest.fixture
def wrong_ca_cert():
    return _make_ca_key_and_cert(cn="Evil CA")


# ---- tests ----

class TestHostnameVerification:
    def test_exact_hostname_match(self):
        from networking.mtls_client import _match_hostname
        assert _match_hostname("inventory.windward.internal", "inventory.windward.internal") is True

    def test_exact_hostname_mismatch(self):
        from networking.mtls_client import _match_hostname
        assert _match_hostname("inventory.windward.internal", "routing.windward.internal") is False

    def test_wildcard_match_single_level(self):
        from networking.mtls_client import _match_hostname
        assert _match_hostname("inventory.windward.internal", "*.windward.internal") is True

    def test_wildcard_no_match_base_domain(self):
        from networking.mtls_client import _match_hostname
        assert _match_hostname("windward.internal", "*.windward.internal") is False

    def test_wildcard_match_different_subdomain(self):
        from networking.mtls_client import _match_hostname
        assert _match_hostname("routing.windward.internal", "*.windward.internal") is True


class TestCertificateExpiry:
    def test_valid_cert_not_expired(self, valid_server_cert):
        from networking.mtls_client import _check_cert_expiry
        _, cert = valid_server_cert
        assert _check_cert_expiry(cert) is True

    def test_expired_cert_rejected(self, expired_server_cert):
        from networking.mtls_client import _check_cert_expiry
        _, cert = expired_server_cert
        assert _check_cert_expiry(cert) is False


class TestCertificateChainValidation:
    def test_valid_chain(self, ca_pair, valid_server_cert):
        from networking.mtls_client import _validate_cert_chain
        _, ca_cert = ca_pair
        _, server_cert = valid_server_cert
        assert _validate_cert_chain(server_cert, ca_cert) is True

    def test_invalid_chain_wrong_ca(self, wrong_ca_cert, valid_server_cert):
        from networking.mtls_client import _validate_cert_chain
        _, wrong_ca = wrong_ca_cert
        _, server_cert = valid_server_cert
        assert _validate_cert_chain(server_cert, wrong_ca) is False


class TestMTLSClient:
    @patch("networking.mtls_client.ssl.SSLContext")
    def test_client_creation(self, mock_ssl_ctx):
        from networking.mtls_client import MTLSClient
        from networking.config import TLSConfig
        config = TLSConfig(
            ca_bundle_path="/tmp/fake-ca.pem",
            client_cert_path="/tmp/fake-cert.pem",
            client_key_path="/tmp/fake-key.pem",
        )
        client = MTLSClient(config)
        assert client is not None

    @patch("networking.mtls_client.ssl.SSLContext")
    def test_client_default_config(self, mock_ssl_ctx):
        from networking.mtls_client import MTLSClient
        client = MTLSClient()
        assert client is not None
